package io.github.gabriel0liv.cpmconverter.validator;

import com.fasterxml.jackson.databind.JsonNode;
import io.github.gabriel0liv.cpmconverter.diagnostics.*;
import java.util.*;

final class CpmPersistedConfigValidator {
  private static final Set<String> TOP=Set.of("version","skinType","skinSize","textures","elements");
  Result<CpmValidatedConfigV1> validate(JsonNode root){var bag=new DiagnosticBag(); for(var it=root.fieldNames();it.hasNext();){String f=it.next();if(!TOP.contains(f))bag=bag.add(error(DiagnosticCodes.CPM_FEATURE_UNSUPPORTED,"/"+f,"unsupported config property"));} JsonNode v=root.get("version"),e=root.get("elements"); if(v==null||!v.isIntegralNumber())bag=bag.add(error(DiagnosticCodes.CPM_CONFIG_INVALID,"/version","version must be an integer")); else if(v.intValue()!=1)bag=bag.add(error(DiagnosticCodes.CPM_UNSUPPORTED_VERSION,"/version","unsupported version")); if(e==null||!e.isArray())bag=bag.add(error(DiagnosticCodes.CPM_CONFIG_INVALID,"/elements","elements must be an array")); JsonNode skinNode=root.get("skinType"); String skin="default"; if(skinNode!=null){if(!skinNode.isTextual())bag=bag.add(error(DiagnosticCodes.CPM_CONFIG_INVALID,"/skinType","skinType must be a string")); else {skin=skinNode.textValue(); if(!skin.equals("default")&&!skin.equals("slim"))bag=bag.add(error(DiagnosticCodes.CPM_CONFIG_INVALID,"/skinType","unsupported skinType"));}} JsonNode size=root.get("skinSize"); int sx=64,sy=64; if(size!=null){if(!size.isObject())bag=bag.add(error(DiagnosticCodes.CPM_CONFIG_INVALID,"/skinSize","skinSize must be object")); else {for(var it=size.fieldNames();it.hasNext();) {String f=it.next();if(!f.equals("x")&&!f.equals("y"))bag=bag.add(error(DiagnosticCodes.CPM_CONFIG_INVALID,"/skinSize/"+f,"unknown skinSize field"));} JsonNode x=size.get("x"),y=size.get("y"); if(x==null||!x.isIntegralNumber()||x.intValue()<=0)bag=bag.add(error(DiagnosticCodes.CPM_CONFIG_INVALID,"/skinSize/x","x must be positive integer")); else sx=x.intValue(); if(y==null||!y.isIntegralNumber()||y.intValue()<=0)bag=bag.add(error(DiagnosticCodes.CPM_CONFIG_INVALID,"/skinSize/y","y must be positive integer")); else sy=y.intValue();}} JsonNode textures=root.get("textures"); boolean custom=false,anim=false; if(textures!=null){if(!textures.isObject())bag=bag.add(error(DiagnosticCodes.CPM_CONFIG_INVALID,"/textures","textures must be object")); else {for(var it=textures.fieldNames();it.hasNext();) {String f=it.next();if(!f.equals("skin"))bag=bag.add(error(DiagnosticCodes.CPM_FEATURE_UNSUPPORTED,"/textures/"+f,"unsupported texture field"));} JsonNode s=textures.get("skin"); if(s!=null){if(!s.isObject())bag=bag.add(error(DiagnosticCodes.CPM_CONFIG_INVALID,"/textures/skin","skin texture object required")); else {for(var it=s.fieldNames();it.hasNext();) {String f=it.next();if(!f.equals("customGridSize")&&!f.equals("anim"))bag=bag.add(error(DiagnosticCodes.CPM_FEATURE_UNSUPPORTED,"/textures/skin/"+f,"unsupported skin texture field"));} JsonNode cg=s.get("customGridSize"); if(cg!=null){if(!cg.isBoolean())bag=bag.add(error(DiagnosticCodes.CPM_CONFIG_INVALID,"/textures/skin/customGridSize","customGridSize must be boolean")); else custom=cg.booleanValue();} JsonNode an=s.get("anim"); if(an!=null){if(!an.isArray())bag=bag.add(error(DiagnosticCodes.CPM_CONFIG_INVALID,"/textures/skin/anim","anim must be array")); else {anim=!an.isEmpty();if(anim)bag=bag.add(error(DiagnosticCodes.CPM_FEATURE_UNSUPPORTED,"/textures/skin/anim","animated textures unsupported"));}}}}}} if(bag.hasErrors())return Result.failure(bag); return Result.success(new CpmValidatedConfigV1(root,1,skin,new CpmPersistedSize2i(sx,sy),custom,anim),bag); }
  private static Diagnostic error(String c,String p,String m){return new Diagnostic(Severity.ERROR,DiagnosticCode.fromCatalog(c),new SourceLocation(new SourcePath("config.json"),null,null,p,null),m,"repair config.json",null,null,new TreeMap<>());}
}
